import React, { useState, useMemo } from "react";
import styles from "./FindJobPage.module.css";
import { MainLayout } from "../../layouts";
import { useLanguage } from "../../translet/LanguageContext";

// Mock job dataset (could be replaced by API later)
const JOBS = [
  { id:1, title:"Senior Frontend Engineer", company:"NovaTech", location:"Ho Chi Minh", category:"Engineering", level:"Senior", type:"Full-time", tags:["React","TypeScript","UI"], desc:"Build and optimize high performance user interfaces used by thousands of interpreters and recruiters." },
  { id:2, title:"Interpreter (EN-VI)", company:"GlobalWords", location:"Hanoi", category:"Translation", level:"Mid", type:"Contract", tags:["EN-VI","On-site","Business"], desc:"Provide on-site and remote interpretation for enterprise clients in business meetings." },
  { id:3, title:"Backend Node.js Developer", company:"CloudBase", location:"Remote", category:"Engineering", level:"Mid", type:"Full-time", tags:["Node.js","API","SQL"], desc:"Design resilient APIs, improve scalability and integrate third-party services." },
  { id:4, title:"Project Coordinator", company:"BridgeWorks", location:"Da Nang", category:"Operations", level:"Junior", type:"Full-time", tags:["Coordination","Scheduling"], desc:"Coordinate interpreter assignments, scheduling, and client communications." },
  { id:5, title:"AI Matching Specialist", company:"G-Bridge", location:"Remote", category:"Data", level:"Mid", type:"Full-time", tags:["AI","Matching","Optimization"], desc:"Refine and monitor AI-based job & candidate matching algorithms." },
  { id:6, title:"Sales Account Executive", company:"LinguaCorp", location:"Ho Chi Minh", category:"Sales", level:"Mid", type:"Full-time", tags:["B2B","KPIs","Growth"], desc:"Drive new business acquisition and manage enterprise client relationships." },
  { id:7, title:"Junior QA Tester", company:"QualityHub", location:"Hanoi", category:"Engineering", level:"Junior", type:"Internship", tags:["Testing","Automation"], desc:"Assist in test case creation and automated regression coverage expansion." },
  { id:8, title:"Talent Acquisition Partner", company:"G-Bridge", location:"Ho Chi Minh", category:"HR", level:"Senior", type:"Full-time", tags:["Recruitment","Strategy"], desc:"Own end-to-end hiring funnel for technical & language roles." },
  { id:9, title:"Localization Manager", company:"WorldSync", location:"Remote", category:"Translation", level:"Senior", type:"Full-time", tags:["Localization","Management"], desc:"Lead localization strategy and process improvements across product lines." },
  { id:10, title:"Data Analyst", company:"InsightOps", location:"Ho Chi Minh", category:"Data", level:"Junior", type:"Full-time", tags:["SQL","Dashboard","ETL"], desc:"Develop dashboards and perform exploratory analysis on marketplace metrics." }
];

const unique = (arr) => Array.from(new Set(arr));

export default function FindJobPage() {
  const { t } = useLanguage();
  const [keyword, setKeyword] = useState("");
  const [location, setLocation] = useState("");
  const [category, setCategory] = useState("");
  const [page, setPage] = useState(1);
  const pageSize = 9; // 3 x 3 layout

  const categories = useMemo(()=> unique(JOBS.map(j=> j.category)), []);
  const locations = useMemo(()=> unique(JOBS.map(j=> j.location)), []);

  const filtered = useMemo(()=> {
    return JOBS.filter(j => {
      const kw = keyword.trim().toLowerCase();
      if (kw && !(j.title.toLowerCase().includes(kw) || j.company.toLowerCase().includes(kw) || j.tags.some(tg=> tg.toLowerCase().includes(kw)))) return false;
      if (location && j.location !== location) return false;
      if (category && j.category !== category) return false;
      return true;
    });
  }, [keyword, location, category]);

  const totalPages = Math.ceil(filtered.length / pageSize) || 1;
  const pageSafe = Math.min(page, totalPages);
  const slice = filtered.slice((pageSafe-1)*pageSize, pageSafe*pageSize);

  function submit(e){ e.preventDefault(); setPage(1); }
  function reset(){ setKeyword(""); setLocation(""); setCategory(""); setPage(1); }

  return (
    <MainLayout>
      <div className={styles.findJobRoot}>
        <div className={styles.container}>
          <header className={styles.header}>
            <h1 className={styles.title}>Find Your Next Opportunity</h1>
            <p className={styles.subtitle}>Search roles across engineering, translation, operations and more.</p>
          </header>

          <form className={styles.searchBar} onSubmit={submit}>
            <div className={styles.field}>
              <label>Keyword / Company</label>
              <input value={keyword} onChange={e=> setKeyword(e.target.value)} placeholder="e.g. React, Interpreter" />
            </div>
            <div className={styles.field}>
              <label>Location</label>
              <select value={location} onChange={e=> setLocation(e.target.value)}>
                <option value="">All</option>
                {locations.map(l=> <option key={l} value={l}>{l}</option>)}
              </select>
            </div>
            <div className={styles.field}>
              <label>Category</label>
              <select value={category} onChange={e=> setCategory(e.target.value)}>
                <option value="">All</option>
                {categories.map(c=> <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div className={styles.actions}>
              <button type="submit" className={styles.searchBtn}>Search</button>
              <button type="button" onClick={reset} className={styles.resetBtn}>Reset</button>
            </div>
          </form>

          <div className={styles.jobsGrid}>
            {slice.length === 0 && <div className={styles.empty}>No jobs found.</div>}
            {slice.map(job => (
              <div key={job.id} className={styles.jobCard}>
                <div className={styles.jobTop}>
                  <div className={styles.logo}>{job.company[0]}</div>
                  <div className={styles.jobInfo}>
                    <h3 className={styles.jobTitle}>{job.title}</h3>
                    <p className={styles.company}>{job.company}</p>
                    <div className={styles.meta}>
                      <span>{job.location}</span>
                      <span>{job.category}</span>
                      <span>{job.type}</span>
                      <span>{job.level}</span>
                    </div>
                  </div>
                </div>
                <p className={styles.desc}>{job.desc}</p>
                <div className={styles.tags}>{job.tags.map(tg=> <span key={tg}>{tg}</span>)}</div>
                <div className={styles.cardActions}>
                  <button className={styles.applyBtn}>{t('common.apply')}</button>
                  <button className={styles.saveBtn}>{t('common.save')}</button>
                </div>
              </div>
            ))}
          </div>

          <div className={styles.pagination}>
            {Array.from({length: totalPages}).map((_,i)=> {
              const p = i+1;
              return <button key={p} onClick={()=> setPage(p)} className={`${styles.pageBtn} ${p===pageSafe?styles.active:''}`}>{p}</button>;
            })}
          </div>
        </div>
      </div>
    </MainLayout>
  );
}
